What does this program print?

```cpp
#include <iostream>

class Counter {
public:
    static inline int s_count{ 0 };
    Counter() { ++s_count; }
};

int main() {
    Counter a;
    Counter b;
    Counter c;
    std::cout << Counter::s_count << "\n";
}
```

